import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import API from "../api";

const EventDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [tickets, setTickets] = useState(1);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchEvent = async () => {
      try {
        const res = await API.get(`/events/${id}`);
        setEvent(res.data.event);
      } catch (err) {
        console.log(err);
      }
    };
    fetchEvent();
  }, [id]);

  const handleBooking = async () => {
    try {
      const res = await API.post("/bookings", { eventId: id, numberOfTickets: tickets });
      navigate(`/payments`);
    } catch (err) {
      setError(err.response?.data?.message || "Booking failed");
    }
  };

  if (!event) return <p className="text-center mt-10">Loading...</p>;

  return (
    <div className="container mx-auto p-6">
      <div className="flex flex-col md:flex-row gap-6">
        <img src={event.image} className="w-full md:w-1/2 h-96 object-cover rounded-lg" />
        <div className="flex-1">
          <h1 className="text-3xl font-bold mb-2">{event.name}</h1>
          <p className="text-gray-600 mb-2">{new Date(event.date).toLocaleDateString()} at {event.time}</p>
          <p className="text-gray-600 mb-2">{event.venue}</p>
          <p className="mb-4">{event.description}</p>
          <p className="text-purple-600 font-semibold mb-4">${event.price}</p>
          <div className="flex items-center gap-4">
            <input type="number" min="1" max={event.availableSeats} value={tickets} onChange={(e) => setTickets(e.target.value)} className="border p-2 rounded w-24" />
            <button onClick={handleBooking} className="bg-purple-600 text-white px-4 py-2 rounded">Book Now</button>
          </div>
          {error && <p className="text-red-600 mt-2">{error}</p>}
        </div>
      </div>
    </div>
  );
};

export default EventDetails;
